def cache_key_generator(*args, **kwargs):
    key_data = json.dumps({'args': args, 'kwargs': kwargs}, sort_keys=True)
    return hashlib.md5(key_data.encode()).hexdigest()

def cache_query(ttl=300, prefix='query'):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"{prefix}:{func.__name__}:{cache_key_generator(*args, **kwargs)}"
            
            cached_result = memcache_client.get(cache_key)
            if cached_result is not None:
                return cached_result
            
            result = func(*args, **kwargs)
            memcache_client.set(cache_key, result, expire=ttl)
            
            return result
        return wrapper
    return decorator

def cache_api(ttl=60, prefix='api'):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            request_data = {
                'path': request.path,
                'args': dict(request.args),
                'method': request.method
            }
            cache_key = f"{prefix}:{func.__name__}:{cache_key_generator(request_data)}"
            
            cached_response = memcache_client.get(cache_key)
            if cached_response is not None:
                return cached_response
            
            response = func(*args, **kwargs)
            memcache_client.set(cache_key, response, expire=ttl)
            
            return response
        return wrapper
    return decorator

